-    @Reflect
-    public static vec4 mainImageJulia(Uniforms uniforms, vec4 fragColor, vec2 fragCoord) {
-
-        final int AA = 2;
-        float scol = 0.0f;
-        for( int j=0; j<AA; j++ )
-            for( int i=0; i<AA; i++ ) {
-                vec2 of = add(-0.5f, div(vec2.vec2( (float)i, (float)j ),(float)AA));
