-        scol/=(float)AA*AA;
-
-
-        vec3 vcol = vec3.pow( vec3.vec3(scol), vec3.vec3(0.9f,1.1f,1.4f) );
-        vec2 fres  = vec2.vec2(uniforms.iResolution().x(), uniforms.iResolution().y());
